def get_diagram_svg(m):
 m=m.lower()
 if not any(k in m for k in ["draw","diagram","graph","experiment","illustrate","sketch","plot"]):return None,None,None
 for t in ["transformer","ohm's law","pulley","convex lens"]:
  if re.search(r'\b'+re.escape(t)+r'\b',m):return DIAGRAM_LIBRARY[t],t,None
